/*!
 * marked-lite.js — lightweight markdown renderer for Vulntrix
 * Handles all common AI output patterns: code blocks, headers, lists,
 * bold/italic, links, blockquotes, tables, horizontal rules.
 * Exposes the same marked.parse() / marked.setOptions() API as marked.js.
 */
(function (global) {
  'use strict';

  var _opts = { breaks: true, gfm: true };

  function escHtml(s) {
    return String(s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function parse(src) {
    if (!src) return '';

    var lines = src.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
    var html  = '';
    var i     = 0;
    var arr   = lines.split('\n');
    var len   = arr.length;

    function peek(offset) { return arr[i + (offset || 1)] || ''; }
    function cur()        { return arr[i]; }

    while (i < len) {
      var line = cur();

      // ── Fenced code block ───────────────────────────────
      var fenceMatch = line.match(/^(`{3,}|~{3,})\s*(\S*)/);
      if (fenceMatch) {
        var fence   = fenceMatch[1];
        var lang    = escHtml(fenceMatch[2] || '');
        var code    = [];
        i++;
        while (i < len && !arr[i].startsWith(fence)) {
          code.push(arr[i]);
          i++;
        }
        i++; // skip closing fence
        var codeHtml = escHtml(code.join('\n'));
        html += '<pre><code' + (lang ? ' class="language-' + lang + '"' : '') + '>' +
                codeHtml + '</code></pre>\n';
        continue;
      }

      // ── Horizontal rule ─────────────────────────────────
      if (/^(\-{3,}|\*{3,}|_{3,})\s*$/.test(line)) {
        html += '<hr>\n'; i++; continue;
      }

      // ── ATX heading ─────────────────────────────────────
      var headMatch = line.match(/^(#{1,6})\s+(.+)/);
      if (headMatch) {
        var level = headMatch[1].length;
        html += '<h' + level + '>' + inline(headMatch[2]) + '</h' + level + '>\n';
        i++; continue;
      }

      // ── Blockquote ──────────────────────────────────────
      if (/^>\s?/.test(line)) {
        var bqLines = [];
        while (i < len && /^>\s?/.test(arr[i])) {
          bqLines.push(arr[i].replace(/^>\s?/, ''));
          i++;
        }
        html += '<blockquote>' + parse(bqLines.join('\n')) + '</blockquote>\n';
        continue;
      }

      // ── Unordered list ──────────────────────────────────
      if (/^[\*\-\+]\s/.test(line)) {
        html += '<ul>\n';
        while (i < len && /^[\*\-\+]\s/.test(arr[i])) {
          html += '<li>' + inline(arr[i].replace(/^[\*\-\+]\s/, '')) + '</li>\n';
          i++;
        }
        html += '</ul>\n';
        continue;
      }

      // ── Ordered list ────────────────────────────────────
      if (/^\d+\.\s/.test(line)) {
        html += '<ol>\n';
        while (i < len && /^\d+\.\s/.test(arr[i])) {
          html += '<li>' + inline(arr[i].replace(/^\d+\.\s/, '')) + '</li>\n';
          i++;
        }
        html += '</ol>\n';
        continue;
      }

      // ── Table (GFM) ─────────────────────────────────────
      if (/\|/.test(line) && i + 1 < len && /^\|?\s*[-:]+[-| :]*\|/.test(peek())) {
        var headers = splitTableRow(line);
        i++; // skip separator
        i++;
        html += '<table>\n<thead><tr>';
        headers.forEach(function (h) {
          html += '<th>' + inline(h.trim()) + '</th>';
        });
        html += '</tr></thead>\n<tbody>\n';
        while (i < len && /\|/.test(arr[i]) && arr[i].trim() !== '') {
          var cells = splitTableRow(arr[i]);
          html += '<tr>';
          cells.forEach(function (c) { html += '<td>' + inline(c.trim()) + '</td>'; });
          html += '</tr>\n';
          i++;
        }
        html += '</tbody></table>\n';
        continue;
      }

      // ── Blank line ──────────────────────────────────────
      if (line.trim() === '') {
        i++; continue;
      }

      // ── Paragraph ───────────────────────────────────────
      var paraLines = [];
      while (i < len && arr[i].trim() !== '' &&
             !/^(#{1,6}\s|`{3,}|~{3,}|[\*\-\+]\s|\d+\.\s|>\s?)/.test(arr[i]) &&
             !/^(\-{3,}|\*{3,}|_{3,})\s*$/.test(arr[i])) {
        paraLines.push(arr[i]);
        i++;
      }
      if (paraLines.length) {
        var sep = _opts.breaks ? '<br>\n' : '\n';
        html += '<p>' + inline(paraLines.join(sep)) + '</p>\n';
      }
    }

    return html;
  }

  function splitTableRow(row) {
    return row.replace(/^\||\|$/g, '').split('|');
  }

  // ── Inline formatting ────────────────────────────────────
  function inline(s) {
    // 1. Escape HTML first
    s = escHtml(s);

    // 2. Protect inline code spans — replace with placeholders so nothing
    //    inside backticks gets further processed
    var codeSlots = [];
    s = s.replace(/`([^`]+)`/g, function (_, inner) {
      codeSlots.push('<code>' + inner + '</code>');
      return '\x00CODE' + (codeSlots.length - 1) + '\x00';
    });

    // 3. Markdown links [text](url) — must come BEFORE auto-link so the URL
    //    inside () is never independently processed
    s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g,
      '<a href="$2" target="_blank" rel="noopener">$1</a>');

    // 4. Auto-link bare URLs that are NOT already inside an href attribute
    s = s.replace(/(?<!href=")https?:\/\/[^\s<>"]+/g, function (url) {
      return '<a href="' + url + '" target="_blank" rel="noopener">' + url + '</a>';
    });

    // 5. Bold + italic ***text***
    s = s.replace(/\*{3}(.+?)\*{3}/g, '<strong><em>$1</em></strong>');
    s = s.replace(/_{3}(.+?)_{3}/g,   '<strong><em>$1</em></strong>');

    // 6. Bold **text** / __text__
    s = s.replace(/\*{2}(.+?)\*{2}/g, '<strong>$1</strong>');
    s = s.replace(/_{2}(.+?)_{2}/g,   '<strong>$1</strong>');

    // 7. Italic *text* / _text_ (not inside words for underscore)
    s = s.replace(/\*(.+?)\*/g, '<em>$1</em>');
    s = s.replace(/(?<![a-zA-Z])_(.+?)_(?![a-zA-Z])/g, '<em>$1</em>');

    // 8. Strikethrough ~~text~~
    s = s.replace(/~~(.+?)~~/g, '<del>$1</del>');

    // 9. Restore code placeholders
    s = s.replace(/\x00CODE(\d+)\x00/g, function (_, idx) {
      return codeSlots[+idx];
    });

    return s;
  }

  // ── Public API (matches marked.js surface) ───────────────
  var marked = {
    parse:      parse,
    setOptions: function (opts) { Object.assign(_opts, opts); },
    options:    _opts,
  };

  // Support both module environments and plain <script> tags
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = marked;
  } else {
    global.marked = marked;
  }

}(typeof globalThis !== 'undefined' ? globalThis : this));
